proof fn phi_1_temp_pred_equality_collapses_distinct()
    ensures
        TempPred::<int>::new(|ex: Execution<int>| true) == TempPred::<int>::new(|ex: Execution<int>| true),
{
    let p = TempPred::<int>::new(|ex: Execution<int>| true);
    let q = TempPred::<int>::new(|ex: Execution<int>| true);
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_entails_antisymmetry_forces_equality(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p.pred == q.pred,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_a_to_temp_pred_equality_forces_fn_equality(
    p: spec_fn(bool) -> TempPred<int>,
    q: spec_fn(bool) -> TempPred<int>,
)
    requires
        forall |a: bool| #[trigger] p(a).entails(q(a)) && q(a).entails(p(a)),
    ensures
        p == q,
{
    a_to_temp_pred_equality::<int, bool>(p, q);
}

proof fn phi_4_trivial_mutual_entailment()
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false) == TempPred::<int>::new(|ex: Execution<int>| false),
{
    let p = TempPred::<int>::new(|ex: Execution<int>| false);
    let q = TempPred::<int>::new(|ex: Execution<int>| false);
    temp_pred_equality::<int>(p, q);
}
